    if (!(classType instanceof ParameterizedType)) {
        return;
    }
    ParameterizedType parameterizedType = (ParameterizedType) classType;
    TypeVariable[] typeParameters = ((Class<?>) parameterizedType.getRawType()).getTypeParameters();
    Type[] actualTypeArguments = parameterizedType.getActualTypeArguments();
    for (int i = 0; i < actualTypeArguments.length; i++) {
        TypeVariable typeParameter = typeParameters[i];
        Type actualTypeArgument = actualTypeArguments[i];

        if (actualTypeArgument instanceof WildcardType) {
            contextualActualTypeParameters.put(typeParameter, boundsOf((WildcardType) actualTypeArgument));
        } else {
            contextualActualTypeParameters.put(typeParameter, actualTypeArgument);
        }
        // logger.log("For '" + parameterizedType + "' found type variable : { '" + typeParameter + "(" + System.identityHashCode(typeParameter) + ")" + "' : '" + actualTypeArgument + "(" + System.identityHashCode(typeParameter) + ")" + "' }");
    }
}

fix:
protected void addType variablesOn(Type classType) {
        if !(classType instanceof Parameterized type){return; }
        Parameterized type parameterized type = ( parameterized type) classType;
        Type variable[] type parameters =((class type) parameterized type.get Raw type). get type parameters();
        Type actual type[] type parameters = parameterized type. get actual type parameters();
        for int i= 0; i < actual type[] type parameters.length; i++{
            type variable[] type parameter = variable type parameters[i];
            type actual type[] type parameter = actual type[] type parameters[i];

            if actual type[] type parameter instanceof wild card type){
                contextual actual type parameters.put(type variable[] type parameter,Bounds of(( wild card type) actual type[] type parameter)) ;
            }else{
                contextual actual type parameters.put(type variable[] type parameter, actual type[] type parameter);
            }
        }
    }

    @ test
    public void type variable _ self type () {
        add type variables on(generics self reference class. infer from(generics self reference class. class);
        assertThat(infer from(generics self reference class. class). infer generics self reference class. resolves type variable (first named method("self",generics self reference class. class)) .raw type()) .is equal to(generics self reference class. class);
    }

issue_description:
Add this to GenericMetadataSupportTest:
    interface GenericsSelfReference<T extends GenericsSelfReference<T>> {
        T self();
    }

    @Test
    public void typeVariable_of_self_type() {
        GenericMetadataSupport genericMetadata = inferFrom(GenericsSelfReference.class).resolveGenericReturnType(firstNamedMethod("self", GenericsSelfReference.class));

        assertThat(genericMetadata.rawType()).isEqualTo(GenericsSelfReference.class);
    }
It fails on master and 1.10.8 with this:
java.lang.StackOverflowError
    at sun.reflect.generics.reflectiveObjects.TypeVariableImpl.hashCode(TypeVariableImpl.java:201)
    at java.util.HashMap.hash(HashMap.java:338)
    at java.util.HashMap.get(HashMap.java:556)
    at org.mockito.internal.util.reflection.GenericMetadataSupport.getActualTypeArgumentFor(GenericMetadataSupport.java:193)
    at org.mockito.internal.util.reflection.GenericMetadataSupport.getActualTypeArgumentFor(GenericMetadataSupport.java:196)
    at org.mockito.internal.util.reflection.GenericMetadataSupport.getActualTypeArgumentFor(GenericMetadataSupport.java:196)

It worked on 1.9.5. May be caused by the changes in ab9e9f3 (cc @bric3).
(Also note that while the above interface looks strange, it is commonly used for builder hierarchies, where base class methods want to return this with a more specific type.)

